import React, { useState } from 'react';
import axios from 'axios';
import { Save, Plus, Trash2, FileSpreadsheet, AlertCircle, Loader2 } from 'lucide-react';

const GestionInventario = ({ localId, onComplete }) => {
    // Iniciamos con 5 filas vacías como un Excel real
    const [filas, setFilas] = useState([
        { tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '' },
        { tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '' },
        { tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '' },
    ]);
    const [loading, setLoading] = useState(false);

    const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

    // Manejar cambios en celdas específicas
    const handleCellChange = (index, field, value) => {
        const nuevasFilas = [...filas];
        nuevasFilas[index][field] = value;
        setFilas(nuevasFilas);
    };

    // Agregar fila nueva (como el "+" de Excel)
    const agregarFila = () => {
        setFilas([...filas, { tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '' }]);
    };

    // Eliminar fila específica
    const eliminarFila = (index) => {
        setFilas(filas.filter((_, i) => i !== index));
    };

    const handleGuardarTodo = async () => {
        // Filtramos solo las filas que tienen datos
        const productosValidos = filas.filter(f => f.tipo && f.marca && f.precioNuevo);
        
        if (productosValidos.length === 0) {
            alert("Completa al menos una fila con Tipo, Marca y Precio.");
            return;
        }

        setLoading(true);
        try {
            const payload = {
                localId,
                productos: productosValidos.map(p => ({
                    ...p,
                    producto: `${p.tipo} ${p.marca} ${p.contenido}`.trim()
                }))
            };
            await axios.post(`${API_URL}/api/ofertas/bulk`, payload);
            alert("¡Datos guardados exitosamente!");
            setFilas([{ tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '' }]);
            onComplete();
        } catch (error) {
            alert("Error al guardar: " + error.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={excelContainer}>
            <div style={excelHeader}>
                <div style={{display:'flex', alignItems:'center', gap:'10px'}}>
                    <FileSpreadsheet color="#107c41" size={28} />
                    <h3 style={{margin:0}}>Editor de Carga Rápida</h3>
                </div>
                <div style={{fontSize:'0.8rem', color:'#64748b'}}>
                    Escribe directamente en las celdas · Los borradores no se publican hasta que tú lo decidas
                </div>
            </div>

            <div style={tableWrapper}>
                <table style={tableStyle}>
                    <thead>
                        <tr>
                            <th style={thStyle}>Tipo / Producto</th>
                            <th style={thStyle}>Marca</th>
                            <th style={thStyle}>Contenido</th>
                            <th style={thStyle}>Categoría</th>
                            <th style={thStyle}>Precio Oferta</th>
                            <th style={thStyle}>Precio Normal</th>
                            <th style={thStyle}>Stock</th>
                            <th style={{...thStyle, width: '50px'}}></th>
                        </tr>
                    </thead>
                    <tbody>
                        {filas.map((fila, index) => (
                            <tr key={index} style={trStyle}>
                                <td style={tdStyle}><input style={inputCell} value={fila.tipo} onChange={(e) => handleCellChange(index, 'tipo', e.target.value)} placeholder="Ej: Fideos" /></td>
                                <td style={tdStyle}><input style={inputCell} value={fila.marca} onChange={(e) => handleCellChange(index, 'marca', e.target.value)} placeholder="Ej: Lucchetti" /></td>
                                <td style={tdStyle}><input style={inputCell} value={fila.contenido} onChange={(e) => handleCellChange(index, 'contenido', e.target.value)} placeholder="Ej: 500g" /></td>
                                <td style={tdStyle}>
                                    <select style={inputCell} value={fila.categoria} onChange={(e) => handleCellChange(index, 'categoria', e.target.value)}>
                                        <option value="Almacén">Almacén</option>
                                        <option value="Bebidas">Bebidas</option>
                                        <option value="Limpieza">Limpieza</option>
                                        <option value="Fiambrería">Fiambrería</option>
                                    </select>
                                </td>
                                <td style={tdStyle}><input style={inputCell} type="number" value={fila.precioNuevo} onChange={(e) => handleCellChange(index, 'precioNuevo', e.target.value)} placeholder="0.00" /></td>
                                <td style={tdStyle}><input style={inputCell} type="number" value={fila.precioViejo} onChange={(e) => handleCellChange(index, 'precioViejo', e.target.value)} placeholder="Opcional" /></td>
                                <td style={tdStyle}><input style={inputCell} type="number" value={fila.stock} onChange={(e) => handleCellChange(index, 'stock', e.target.value)} placeholder="Cant." /></td>
                                <td style={tdActionStyle}>
                                    <button onClick={() => eliminarFila(index)} style={btnDel}><Trash2 size={14}/></button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            <div style={excelFooter}>
                <button onClick={agregarFila} style={btnAddRow}>
                    <Plus size={18}/> Agregar Fila
                </button>
                <button onClick={handleGuardarTodo} style={btnSaveExcel} disabled={loading}>
                    {loading ? <Loader2 className="animate-spin" size={18}/> : <Save size={18}/>}
                    Guardar Cambios en Inventario
                </button>
            </div>
        </div>
    );
};

// --- ESTILOS EXCEL ---
const excelContainer = { background: 'white', borderRadius: '12px', border: '1px solid #e2e8f0', marginBottom: '30px', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' };
const excelHeader = { padding: '15px 20px', borderBottom: '1px solid #e2e8f0', background: '#f8fafc', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const tableWrapper = { overflowX: 'auto' };
const tableStyle = { width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' };
const thStyle = { textAlign: 'left', padding: '12px', background: '#f1f5f9', color: '#475569', fontWeight: '600', borderBottom: '2px solid #e2e8f0' };
const trStyle = { borderBottom: '1px solid #f1f5f9' };
const tdStyle = { padding: '5px' };
